import json

with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def to_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                m[key] = pkg['resolvedVersion']
    return m

b = to_map(baseline)
a = to_map(after)

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    proj, fw, pkg = key
    bv = b.get(key)
    av = a.get(key)
    if bv != av:
        changes.append((proj, fw, pkg, bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((proj, fw, pkg, av))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]} [{c[1]}] {c[2]}: {c[3]} -> {c[4]}')
else:
    print('None')

print()
print(f'=== UNCHANGED: {len(unchanged)} packages ===')
"

